package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.FileInputStream;
import java.io.InputStreamReader;
import java.lang.reflect.Field;
import java.nio.charset.Charset;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVParserParseFileTest {

    private File mockFile;
    private Charset charset;
    private CSVFormat format;

    @BeforeEach
    void setUp() {
        mockFile = mock(File.class);
        charset = Charset.defaultCharset();
        format = mock(CSVFormat.class);
    }

    @Test
    void testParseFileSuccess() throws Exception {
        // Since Mockito 3 does not support mockConstruction, avoid mocking constructors.
        // Instead, mock FileInputStream and InputStreamReader if needed or rely on real construction with mocks.
        // Here we just call parse with mocks and check the internal state.

        CSVParser parser = CSVParser.parse(mockFile, charset, format);
        assertNotNull(parser);

        Field formatField = CSVParser.class.getDeclaredField("format");
        formatField.setAccessible(true);
        assertSame(format, formatField.get(parser));
    }

    @Test
    void testParseFileNullFile() {
        NullPointerException thrown = assertThrows(NullPointerException.class,
                () -> CSVParser.parse((File) null, charset, format));
        assertEquals("file", thrown.getMessage());
    }

    @Test
    void testParseFileNullFormat() {
        NullPointerException thrown = assertThrows(NullPointerException.class,
                () -> CSVParser.parse(mockFile, charset, null));
        assertEquals("format", thrown.getMessage());
    }
}
